module RefModule(
  input clk,
  input reset,
  input enable,
  output reg [3:0] lfsr_out
);reg [3:0] obf_lfsr_reg;

always @(posedge clk) begin
  if (reset) begin
    obf_lfsr_reg <= 4'b0001;
  end else if (enable) begin
    obf_lfsr_reg <= {obf_lfsr_reg[2:0], obf_lfsr_reg[3] ^ obf_lfsr_reg[0]};
  end
end

assign lfsr_out = obf_lfsr_reg;

endmodule
